public fun CoroutineScope.launch(
    context: CoroutineContext = EmptyCoroutineContext,
    start: CoroutineStart = CoroutineStart.DEFAULT,
    block: suspend CoroutineScope.() -> Unit
): Job {
    val newContext = newCoroutineContext(context)
    val coroutine = if (start.isLazy)
        LazyStandaloneCoroutine(newContext, block) else
        StandaloneCoroutine(newContext, active = true)
    coroutine.start(start, coroutine, block)
    return coroutine
}

override fun enqueue(request: ImageRequest): Disposable {
    // Start executing the request on the main thread.
    val job = scope.async(options.mainCoroutineContextLazy.value) {
        execute(request, REQUEST_TYPE_ENQUEUE)
    }

    // Update the current request attached to the view and return a new disposable.
    return getDisposable(request, job)
}

fun newFetcher(
    data: Any,
    options: Options,
    imageLoader: ImageLoader,
    startIndex: Int = 0,
): Pair<Fetcher, Int>? {
    for (index in startIndex until fetcherFactories.size) {
        val (factory, type) = fetcherFactories[index]
        if (type.isInstance(data)) {
            val fetcher = (factory as Fetcher.Factory<Any>).create(data, options, imageLoader)
            if (fetcher != null) return fetcher to index
        }
    }
    return null
}

fun newDecoder(
    result: SourceFetchResult,
    options: Options,
    imageLoader: ImageLoader,
    startIndex: Int = 0,
): Pair<Decoder, Int>? {
    for (index in startIndex until decoderFactories.size) {
        val factory = decoderFactories[index]
        val decoder = factory.create(result, options, imageLoader)
        if (decoder != null) return decoder to index
    }
    return null
}

internal fun <T> resolveInstance(
    qualifier: Qualifier?,
    clazz: KClass<*>,
    scopeQualifier: Qualifier,
    instanceContext: ResolutionContext,
): T? {
    val factory = resolveDefinition(clazz, qualifier, scopeQualifier) ?: return null
    return try {
        factory.get(instanceContext) as? T
    } catch (e: org.koin.core.error.MissingScopeValueException) {
        null
    }
}

fun indexPrimaryType(instanceFactory: InstanceFactory<*>) {
    val def = instanceFactory.beanDefinition
    val mapping = indexKey(def.primaryType, def.qualifier, def.scopeQualifier)
    saveMapping(mapping, instanceFactory)
}

@KoinInternalApi
fun indexSecondaryTypes(instanceFactory: InstanceFactory<*>) {
    val def = instanceFactory.beanDefinition
    def.secondaryTypes.forEach { clazz ->
        val mapping = indexKey(clazz, def.qualifier, def.scopeQualifier)
        saveMapping(mapping, instanceFactory)
    }
}

override fun <T> encodeSerializableValue(serializer: SerializationStrategy<T>, value: T) {
    encodePolymorphically(serializer, value) { discriminatorName, serialName ->
        polymorphicDiscriminator = discriminatorName
        polymorphicSerialName = serialName
    }
}

private fun encodeTypeInfo(discriminator: String, serialName: String) {
    composer.nextItem()
    encodeString(discriminator)
    composer.print(COLON)
    composer.space()
    encodeString(serialName)
}

public final override fun serialize(encoder: Encoder, value: T) {
    val actualSerializer = findPolymorphicSerializer(encoder, value)
    encoder.encodeStructure(descriptor) {
        encodeStringElement(descriptor, 0, actualSerializer.descriptor.serialName)
        encodeSerializableElement(descriptor, 1, actualSerializer.cast(), value)
    }
}

public fun intercept(phase: PipelinePhase, block: PipelineInterceptor<TSubject, TContext>) {
    val phaseContent = findPhase(phase)
        ?: throw InvalidPhaseException("Phase $phase was not registered for this pipeline")

    if (tryAddToPhaseFastPath(phase, block)) {
        interceptorsQuantity++
        return
    }

    phaseContent.addInterceptor(block)
    interceptorsQuantity++
    resetInterceptorsList()

    afterIntercepted()
}

public suspend fun interceptor(context: PipelineContext<Unit, PipelineCall>) {
    val resolveContext = RoutingResolveContext(this, context.call, tracers)
    when (val resolveResult = resolveContext.resolve()) {
        is RoutingResolveResult.Success ->
            executeResult(context, resolveResult.route, resolveResult.parameters)

        is RoutingResolveResult.Failure ->
            context.call.attributes.put(RoutingFailureStatusCode, resolveResult.errorStatusCode)
    }
}

internal fun LifecycleOwner.registerScopeForLifecycle(
    scope: Scope
) {
    lifecycle.addObserver(
        object : DefaultLifecycleObserver {
            override fun onDestroy(owner: LifecycleOwner) {
                scope.close()
                super.onDestroy(owner)
            }
        }
    )
}

internal fun Continuation<SessionDescription>.resumeAfterSdpCreate(): SdpObserver {
    return object : SdpObserver {
        override fun onCreateSuccess(sdp: SessionDescription?) = resume(requireNotNull(sdp))
        override fun onCreateFailure(error: String?) = resumeWithException(WebRtc.SdpException(error))
        override fun onSetSuccess() = Unit
        override fun onSetFailure(error: String?) = Unit
    }
}

internal fun ParameterSpec.Builder.maybeAddRequiresOptIn(resolver: KotlinResolver, optInFeature: String?): ParameterSpec.Builder {
  if (optInFeature == null) {
    return this
  }

  val annotation = resolver.resolveRequiresOptInAnnotation() ?: return this
  return addAnnotation(AnnotationSpec.builder(annotation).build())
}

private fun IrEnum.Value.enumConstTypeSpec(): TypeSpec {
  return TypeSpec.anonymousClassBuilder()
      .maybeAddDeprecation(deprecationReason)
      .maybeAddRequiresOptIn(context.resolver, optInFeature)
      .maybeAddDescription(description)
      .addSuperclassConstructorParameter("%S", name)
      .build()
}

internal fun addRequiredFields(
    operation: GQLOperationDefinition,
    schema: Schema,
    fragments: Map<String, GQLFragmentDefinition>,
): GQLOperationDefinition {
  val parentType = operation.rootTypeDefinition(schema)!!.name
  return operation.copy(
      selections = operation.selections.addRequiredFields(
          schema = schema,
          fragments = fragments,
          parentType = parentType,
          parentFields = emptySet(),
          isRoot = false,
      )
  )
}

fun layout(codegenSchema: CodegenSchema): SchemaAndOperationsLayout? {
  val candidates = layoutFactories.mapNotNull { it.create(codegenSchema) }
  if (candidates.size > 1) {
    error("Apollo: multiple layouts registered. Check your compiler plugins.")
  }
  return candidates.singleOrNull()
}

override fun prepare() {
