private fun decPermits(): Int {
    while (true) {
        // Decrement the number of available permits.
        val p = _availablePermits.getAndDecrement()
        // Is the number of available permits greater
        // than the maximal one due to an incorrect
        // `release()` call without a preceding `acquire()`?
        if (p > permits) continue
        // The number of permits is correct, return it.
        return p
    }
}

private fun Channel(options: DataChannelReceiveOptions): Channel<WebRtc.DataChannel.Message> {
    return Channel(
        capacity = options.capacity,
        onBufferOverflow = options.onBufferOverflow,
        onUndeliveredElement = options.onUndeliveredElement
    )
}

internal fun NamedType.toParameterSpec(context: JavaContext): ParameterSpec {
  val irType = context.resolver.resolveIrType(type)
  return ParameterSpec
      .builder(
          irType.withoutAnnotations(),
          context.layout.javaPropertyName(graphQlName),
      )
      .addAnnotations(irType.annotations)

      .build()
}

